def gen(rng, size):
    rows = rng.randint(5, 50)
    cols = 'ABCDE'
    def rand_cell():
        return rng.choice(cols) + str(rng.randint(1, rows))
    ops = ['Spreadsheet']
    args = [[rows]]
    for _ in range(max(1, size)):
        r = rng.random()
        if r < 0.4:
            ops.append('setCell')
            args.append([rand_cell(), rng.randint(0, 1000)])
        elif r < 0.55:
            ops.append('resetCell')
            args.append([rand_cell()])
        else:
            def operand():
                if rng.random() < 0.5:
                    return rand_cell()
                return str(rng.randint(0, 1000))
            ops.append('getValue')
            args.append(['=' + operand() + '+' + operand()])
    return [ops, args]

