class Spreadsheet {
    constructor(rows) {
        this.rows = rows;
        this.cells = new Map();
    }
    setCell(cell, value) {
        this.cells.set(cell, value);
    }
    resetCell(cell) {
        this.cells.delete(cell);
    }
    _valueOf(token) {
        const c = token.charCodeAt(0);
        if (c >= 65 && c <= 90) {
            return this.cells.has(token) ? this.cells.get(token) : 0;
        }
        return parseInt(token, 10);
    }
    getValue(formula) {
        const body = formula.slice(1);
        const plus = body.indexOf('+');
        const left = body.slice(0, plus);
        const right = body.slice(plus + 1);
        return this._valueOf(left) + this._valueOf(right);
    }
}
